// src/services/adminApi.js
import axios from "axios";

const ADMIN_API = axios.create({ baseURL: "/api/admin" });
ADMIN_API.interceptors.request.use((config) => {
  const token = localStorage.getItem("token");
  if (token) config.headers.Authorization = `Bearer ${token}`;
  return config;
});

export const loginAdmin = (data) => ADMIN_API.post("/login", data);
export const getOverview = () => ADMIN_API.get("/overview");
export const getUsers = () => ADMIN_API.get("/users");
export const getRiders = () => ADMIN_API.get("/riders");
export const getApprovedCaptains = () => ADMIN_API.get("/captains");
export const getPendingCaptains = () => ADMIN_API.get("/pending-captains");
export const getRides = () => ADMIN_API.get("/rides");
export const approveCaptain = (id) => ADMIN_API.post(`/captain/${id}/approve`);
export const rejectCaptain = (id) => ADMIN_API.post(`/captain/${id}/reject`);
